use p3_baby_bear::BabyBear;
use p3_field::{extension::BinomialExtensionField, AbstractField};
use p3_field::{AbstractExtensionField, PrimeField32};
use sp1_core::stark::GenericVerifierConstraintFolder;

type F = BabyBear;
type EF = BinomialExtensionField<F, 4>;

lazy_static! {
    /// The code generated by the compiler.
    ///
    /// We keep this in a static variable so that we can use native operators.
    pub static ref CUDA_P3_EVAL_CODE: Mutex<Vec<String>> = Mutex::new(Vec::new());

    /// The next available identifier for expressions.
    ///
    /// When we compile expressions like `c = a + b`, allocates an identifier for the output `c`.
    pub static ref CUDA_P3_EVAL_EXPR_CTR: Mutex<usize> = Mutex::new(0);
}

/// Resets [CUDA_P3_EVAL_CODE] for the next compilation.
#[allow(non_snake_case)]
pub fn CUDA_P3_EVAL_CODE_RESET() {
    *CUDA_P3_EVAL_CODE.lock().unwrap() = Vec::new();
}

/// Resets [CUDA_P3_EVAL_EXPR_CTR] for the next compilation.
#[allow(non_snake_case)]
pub fn CUDA_P3_EVAL_EXPR_CTR_RESET() {
    *CUDA_P3_EVAL_EXPR_CTR.lock().unwrap() = 0;
}

#[derive(Debug, Clone, Copy)]
pub enum SymbolicValue {
    Base(F),
    Extension(EF),
    PreprocessedLocal(usize),
    PreprocessedNext(usize),
    MainLocal(usize),
    MainNext(usize),
    IsFirstRow(),
    IsLastRow(),
    IsTransition(),
    Alpha(),
    Accumulator(),
    Intermediate(usize),
}

impl Default for SymbolicValue {
    fn default() -> Self {
        SymbolicValue::Base(F::zero())
    }
}

impl SymbolicValue {
    pub fn id(&self) -> String {
        match self {
            SymbolicValue::Base(value) => format!("bb31_t{{{}}}", value),
            SymbolicValue::Extension(value) => {
                let values: [F; 4] = value.as_base_slice().to_vec().try_into().unwrap();
                format!(
                    "bb31_extension_t({}, {}, {}, {})",
                    values[0], values[1], values[2], values[3]
                )
            }
            SymbolicValue::PreprocessedLocal(id) => format!("prepLocal[{}]", id),
            SymbolicValue::PreprocessedNext(id) => format!("prepNext[{}]", id),
            SymbolicValue::MainLocal(id) => format!("mainLocal[{}]", id),
            SymbolicValue::MainNext(id) => format!("mainNext[{}]", id),
            SymbolicValue::IsFirstRow() => "isFirstRow".to_string(),
            SymbolicValue::IsLastRow() => "isLastRow".to_string(),
            SymbolicValue::IsTransition() => "isTransition".to_string(),
            SymbolicValue::Alpha() => "alpha".to_string(),
            SymbolicValue::Accumulator() => "accumulator".to_string(),
            SymbolicValue::Intermediate(id) => format!("tmp{}", id),
        }
    }

    pub fn alloc() -> Self {
        let mut tmp = CUDA_P3_EVAL_EXPR_CTR.lock().unwrap();
        let id = *tmp;
        *tmp += 1;
        SymbolicValue::Intermediate(id)
    }
}

impl AbstractField for SymbolicValue {
    type F = EF;

    fn zero() -> Self {
        SymbolicValue::Base(F::zero())
    }

    fn one() -> Self {
        SymbolicValue::Base(F::one())
    }

    fn two() -> Self {
        SymbolicValue::Base(F::two())
    }

    fn neg_one() -> Self {
        SymbolicValue::Extension(EF::neg_one())
    }

    fn from_f(f: Self::F) -> Self {
        SymbolicValue::Extension(f)
    }

    fn from_bool(b: bool) -> Self {
        if b {
            SymbolicValue::Extension(EF::one())
        } else {
            SymbolicValue::Extension(EF::zero())
        }
    }

    fn from_canonical_u8(b: u8) -> Self {
        SymbolicValue::Extension(EF::from_canonical_u8(b))
    }

    fn from_canonical_u16(n: u16) -> Self {
        SymbolicValue::Extension(EF::from_canonical_u16(n))
    }

    fn from_canonical_u32(n: u32) -> Self {
        SymbolicValue::Extension(EF::from_canonical_u32(n))
    }

    fn from_canonical_u64(n: u64) -> Self {
        SymbolicValue::Extension(EF::from_canonical_u64(n))
    }

    fn from_canonical_usize(n: usize) -> Self {
        SymbolicValue::Extension(EF::from_canonical_usize(n))
    }

    fn from_wrapped_u32(n: u32) -> Self {
        SymbolicValue::Extension(EF::from_wrapped_u32(n))
    }

    fn from_wrapped_u64(n: u64) -> Self {
        SymbolicValue::Extension(EF::from_wrapped_u64(n))
    }

    fn generator() -> Self {
        SymbolicValue::Extension(EF::generator())
    }
}

impl From<F> for SymbolicValue {
    fn from(b: F) -> Self {
        SymbolicValue::Base(b)
    }
}

impl From<EF> for SymbolicValue {
    fn from(b: EF) -> Self {
        SymbolicValue::Extension(b)
    }
}

impl Add for SymbolicValue {
    type Output = Self;

    fn add(self, rhs: Self) -> Self::Output {
        let mut code = CUDA_P3_EVAL_CODE.lock().unwrap();
        let output = SymbolicValue::alloc();
        code.push(format!(
            "bb31_extension_t {} = {} + {};",
            output.id(),
            self.id(),
            rhs.id()
        ));
        output
    }
}

impl Add<F> for SymbolicValue {
    type Output = Self;

    fn add(self, rhs: F) -> Self::Output {
        let mut code = CUDA_P3_EVAL_CODE.lock().unwrap();
        let output = SymbolicValue::alloc();
        code.push(format!(
            "bb31_extension_t {} = {} + bb31_t{{{}}};",
            output.id(),
            self.id(),
            rhs
        ));
        output
    }
}

impl AddAssign for SymbolicValue {
    fn add_assign(&mut self, rhs: Self) {
        let mut code = CUDA_P3_EVAL_CODE.lock().unwrap();
        code.push(format!("{} += {};", self.id(), rhs.id()));
    }
}

