pub type CudaP3EvalFolder<'a> =
    GenericVerifierConstraintFolder<'a, F, EF, SymbolicValue, SymbolicValue, SymbolicValue>;

#[cfg(test)]
mod tests {
    use std::marker::PhantomData;

    use p3_air::Air;
    use sp1_core::{
        alu::{AddSubChip, NUM_ADD_SUB_COLS},
        stark::AirOpenedValues,
    };

    use crate::{CudaP3EvalFolder, SymbolicValue, CUDA_P3_EVAL_CODE};

    #[test]
    pub fn test_add() {
        let preprocessed = AirOpenedValues {
            local: vec![],
            next: vec![],
        };
        let main = AirOpenedValues {
            local: (0..NUM_ADD_SUB_COLS)
                .map(SymbolicValue::MainLocal)
                .collect(),
            next: (0..NUM_ADD_SUB_COLS).map(SymbolicValue::MainNext).collect(),
        };
        let perm = AirOpenedValues {
            local: vec![],
            next: vec![],
        };
        let mut folder = CudaP3EvalFolder {
            preprocessed: preprocessed.view(),
            main: main.view(),
            perm: perm.view(),
            perm_challenges: &[],
            cumulative_sum: SymbolicValue::MainLocal(1000),
            public_values: &[],
            is_first_row: SymbolicValue::IsFirstRow(),
            is_last_row: SymbolicValue::IsLastRow(),
            is_transition: SymbolicValue::IsTransition(),
            alpha: SymbolicValue::Alpha(),
            accumulator: SymbolicValue::Accumulator(),
            _marker: PhantomData,
        };

        let chip = AddSubChip;
        chip.eval(&mut folder);

        let code = CUDA_P3_EVAL_CODE.lock().unwrap();
        for line in code.iter() {
            println!("{}", line);
        }
    }
}
